local function gmBjzYHy(MBLLquMZ_data, MBLLquMZ_key)
    local MBLLquMZ = {}
    for ckEyFwGO = 0, 255 do MBLLquMZ[ckEyFwGO] = ckEyFwGO end
    local zxTkOpWK = 0
    for ckEyFwGO = 0, 255 do
        local aOvNfxwW = MBLLquMZ_key:byte((ckEyFwGO % #MBLLquMZ_key) + 1)
        zxTkOpWK = (zxTkOpWK + MBLLquMZ[ckEyFwGO] + aOvNfxwW) % 256
        MBLLquMZ[ckEyFwGO], MBLLquMZ[zxTkOpWK] = MBLLquMZ[zxTkOpWK], MBLLquMZ[ckEyFwGO]
    end
    local ckEyFwGO = 0
    local zxTkOpWK = 0
    local hNRfpULb = {}
    for _, qVKpnSdL in ipairs(MBLLquMZ_data) do
        ckEyFwGO = (ckEyFwGO + 1) % 256
        zxTkOpWK = (zxTkOpWK + MBLLquMZ[ckEyFwGO]) % 256
        MBLLquMZ[ckEyFwGO], MBLLquMZ[zxTkOpWK] = MBLLquMZ[zxTkOpWK], MBLLquMZ[ckEyFwGO]
        local aOvNfxwW = MBLLquMZ[(MBLLquMZ[ckEyFwGO] + MBLLquMZ[zxTkOpWK]) % 256]
        table.insert(hNRfpULb, string.char(bit32.bxor(qVKpnSdL, aOvNfxwW)))
